@startuml
title ABSTRACTS's Class Diagram

package "Prototype_AbstractFactory" {
  package Boxes {
    folder Abstracts {
      class Pizza_Box <<A>> {
        + ID : int
        + address : String

        Clone() 
        FinishBoxing()

        getAddress()
        setAddress()
        setID_order()
        setLogo()
      }

      note right of Pizza_Box::Clone(): Prototype pattern method

      ' Relationships to other classes would go here if they existed in this view
    }

    %hide circle

    skinparam rectangleStyle roundCorner=5
    hide empty members
}


skinparam backgroundColor white
@enduml
